/// PageHome, starting page intended on displaying user guide-style information
/// and if the wallet on side is connected then the previous activities in the system
<script setup>
import { ref } from 'vue'
import { fetchReports } from '@/api'
import ReportList from '@/components/ReportList'

const reports = ref([])
const loading = ref(true)

fetchReports()
    .then(fetchedReports => {    
        reports.value = fetchedReports
    })
    .finally(() => loading.value = false)


</script>

<template>   
    
    <report-list :reports="reports" :loading="loading"></report-list>
</template>
