export const getCheckout = async (qty, wallet, verbose=false) => { //implement: if (! canBuy.valueOf) return
    try {
        const res = await fetch(`${SERVICE_URL}/create-checkout-session`, {
          method: "post",
          headers: {
            "Content-Type": "application/json",
            'Authorization': 'Bearer some-auth-token'
            //"x-access-token": "token-value",
          },
          body: JSON.stringify(
            {
                items: [{ id: 1, quantity: qty, }],
                wallet: wallet// e.g. "H2upwiN4Qfj38aYt8GgQREY3dyZaEoDaqjAcs9DotVr4",  
            }),
        })

        if (!res.ok) {
          const message = `An error has occured: ${res.status} - ${res.statusText}`
          throw new Error(message)
        }
        const data = await res.json()
        const fetch_result = {
        //   status: res.status + "-" + res.statusText,
        //   headers: {
        //     "Content-Type": res.headers.get("Content-Type"),
        //     "Content-Length": res.headers.get("Content-Length"),
        //   },
          data: {
            checkout_url: data.url,
            session_id: data.session,
          }
        }
        if (verbose) console.log(`from fetch received:${fetch_result.data.checkout_url} and session:${fetch_result.data.session_id}`)

        return fetch_result.data.checkout_url 
        // doesn't work with a Stripe function, checkout_result = await redirectToCheckout({ sessionId: fetch_result.data.session_id })
        
    } catch (err) {
        throw new Error(err.message)
    }
}

export const getTransferStatus =  async (session_id, verbose=false) => {
  try {
    const res = await fetch(`${SERVICE_URL}/confirm-transfer`, { 
        method: "POST",
        headers: {
        "Content-Type": "application/json",
        'Authorization': 'Bearer some-auth-token'
        },
        body: JSON.stringify({session: session_id}),
    })
    
    if (!res.ok) {
      if (verbose) console.error(`Failed to fetch data:${res} `)
      return { result: 4, stamp: res}
    }
    //{ result: data, stamp: stamp})
    let fetchRes = await res.json()
    if (verbose) console.log(`  fetch result: ${fetchRes.result}`)    
    return fetchRes
  }
  catch (error) {
    if (verbose) console.error(`Failed to fetch data from ${SERVICE_URL}: ${error.message}`)
    return { result: 3, stamp: error.message}
  }
}