export default [
    { // info
        name: 'info',
        path: '/',
        component: require('@/components/PageHome').default,
    },
    { // JUTC activities
        name: 'JUTC activities',
        component: require('@/components/PageActivities').default,
    },
    { // Administrative monitor
        name: 'Jungle',
        component: require('@/components/PageJungle').default,
    },
    { // Purchase
        name: 'Transaction',
        component: require('@/components/PageTransaction').default,
    },
    { // Transaction successful
        name: 'Transfering..',
        path: '/success/:id',
        component: require('@/components/PageSuccessPurchase').default,
          //children: [
            // this will render the UserDetails for these 3 URLs
            // - /users/24
            // - /users/24/profile
            // - /24
            //{ path: 'profile', component: UserDetails, alias: ['/:id', ''] },
          //],
    },
    { // Transaction cancelled
        name:'Cancelled..',
        path: '/cancel',
        component: require('@/components/PageCancel').default,
    },
    { // routing not found
        name: 'NotFound',
        path: '/:pathMatch(.*)*',
        component: require('@/components/PageNotFound').default,
  },
    
]


