<script setup>
import { 
    //computed, 
    ref, 
    onBeforeMount,
    //toRefs 
} from 'vue'

import { 
    useAutoresizeTextarea, formatNumber
} from '@/composables' 
import { useWallet } from 'solana-wallets-vue'

//import { redirectToCheckout} from '@vue-stripe/vue-stripe'
import { gettingTokensLevel, getCheckout} from '@/api'

const DEBUG = true
//import CardPayment from'@/components/CardPayment'

// Form data.
const available_amount = ref(0)
const demanded_amount = ref(0)

const { connected } = useWallet()

const textarea = ref()  
useAutoresizeTextarea(textarea)

// Actions.

const getWithStripe = async (qty) => {
    qty = parseInt(qty)
    const { wallet } = useWallet()

    available_amount.value = Number(await gettingTokensLevel()/1000000000n)
    if (qty === 0 || qty > available_amount.value) return
    
    window.location = await getCheckout(qty, wallet.value.publicKey, DEBUG)
    // as a result of the payment using the above checkout,
    // the user will be redirected to PageSuccessPurchase or PageCancel 
    // but not being returned back here
    return    
}

onBeforeMount( async () => {
    available_amount.value = Number(await gettingTokensLevel()/1000000000n)
})


</script>

<template>
    <div v-if="connected" class="px-8 py-4 border-b">
        <!-- Header field. -->

        <textarea
            ref="textarea"
            rows="1"
            class="text-xl w-full focus:outline-none resize-none mb-3"
            placeholder="How much to drop into your wallet?"  
        ></textarea>

        <div class="flex flex-wrap items-center justify-between -m-2">

            <!-- Amount field. -->
            <div class="relative m-2 mr-4">
                <label> Available: {{ formatNumber(available_amount) }}</label>
                <input
                    type="text"
                    placeholder="amount"
                    class="text-pink-500 rounded-full pl-10 pr-4 py-2 bg-gray-100"
                    @input="demanded_amount = $event.target.value"
                >
            </div>
            <div class="flex items-center space-x-6 m-2 ml-auto">

                <button
                class="text-white px-4 py-2 rounded-full font-semibold" :disabled="false"
                    :class="true ? 'bg-pink-500' : 'bg-pink-300 cursor-not-allowed'"
                    @click="getWithStripe(demanded_amount)"
                >
                    test pay
                </button>

                
            </div>
            <p class="text-gray-500 text-sm"> ("Notice: only whole numbers, fractions will be rounded"
                    use test Visa: 4242 4242 4242 4242) </p>




            <!-- <card-payment :token_amount="demanded_amount"></card-payment>  -->
        </div>
    </div>

</template>
